// And groups predicates with the AND operator between them.
func And(predicates ...predicate.DashboardTemplate) predicate.DashboardTemplate {
	return predicate.DashboardTemplate(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.DashboardTemplate) predicate.DashboardTemplate {
	return predicate.DashboardTemplate(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.DashboardTemplate) predicate.DashboardTemplate {
	return predicate.DashboardTemplate(sql.NotPredicates(p))
}
